1	/*
2	* OFDM deinterleaver
3	*/
4	module deinterleave
5	(
6	    input clock,
7	    input reset,
8	    input enable,
9	
10	    input [7:0] rate,
11	    input [5:0] in_bits,
12	    input input_strobe,
13	
14	    output [1:0] out_bits,
15	    output [1:0] erase,
16	    output output_strobe
17	);
18	
19	wire ht = rate[7];
20	
21	wire [5:0] num_data_carrier = ht? 52: 48;
22	wire [5:0] half_data_carrier = ht? 26: 24;
23	
24	reg [5:0] addra;
25	reg [5:0] addrb;
26	
27	reg [10:0] lut_key;
28	wire [21:0] lut_out;
29	wire [21:0] lut_out_delayed;
30	
31	reg lut_valid;
32	wire lut_valid_delayed;
33	
34	assign erase[0] = lut_out_delayed[21];
35	assign erase[1] = lut_out_delayed[20];
36	
37	wire [2:0] lut_bita = lut_out_delayed[7:5];
38	wire [2:0] lut_bitb = lut_out_delayed[4:2];
39	
40	wire [5:0] bit_outa;
41	wire [5:0] bit_outb;
42	
43	assign out_bits[0] = lut_valid_delayed? bit_outa[lut_bita]: 0;
44	assign out_bits[1] = lut_valid_delayed? bit_outb[lut_bitb]: 0;
45	assign output_strobe = enable & lut_valid_delayed & lut_out_delayed[1];
46	
47	wire [5:0] lut_addra = lut_out[19:14];
48	wire [5:0] lut_addrb = lut_out[13:8];
49	wire lut_done = lut_out[0];
50	
51	reg ram_delay;
52	reg ht_delayed;
53	
54	ram_2port #(.DWIDTH(6), .AWIDTH(6)) ram_inst (
55	    .clka(clock),
56	    .ena(1),
57	    .wea(input_strobe),
58	    .addra(addra),
59	    .dia(in_bits),
60	    .doa(bit_outa),
61	    .clkb(clock),
62	    .enb(1),
63	    .web(0),
64	    .addrb(addrb),
65	    .dib(32'hFFFF),
66	    .dob(bit_outb)
67	);
68	
69	deinter_lut lut_inst (
70	    .clka(clock),
71	    .addra(lut_key),
72	    .douta(lut_out)
73	);
74	
75	delayT #(.DATA_WIDTH(23), .DELAY(2)) delay_inst (
76	    .clock(clock),
77	    .reset(reset),
78	
79	    .data_in({lut_valid, lut_out}),
80	    .data_out({lut_valid_delayed, lut_out_delayed})
81	);
82	
83	
84	localparam S_INPUT = 0;
85	localparam S_GET_BASE = 1;
86	localparam S_OUTPUT = 2;
87	
88	reg [1:0] state;
89	
90	always @(posedge clock) begin
91	    if (reset) begin
92	        addra <= num_data_carrier>>1;
93	        addrb <= 0;
94	
95	        lut_key <= 0;
96	        lut_valid <= 0;
97	        ht_delayed <= 0;
98	
99	        ram_delay <= 0;
100	        state <= S_INPUT;
101	    end else if (enable) begin
102	        ht_delayed <= ht;
103	        if (ht != ht_delayed) begin
104	            addra <= num_data_carrier>>1;
105	        end
106	
107	        case(state)
108	            S_INPUT: begin
109	                if (input_strobe) begin
110	                    if (addra == half_data_carrier-1) begin
111	                        lut_key <= {6'b0, ht, rate[3:0]};
112	                        ram_delay <= 0;
113	                        lut_valid <= 0;
114	                        state <= S_GET_BASE;
115	                    end else begin
116	                        if (addra == num_data_carrier-1) begin
117	                            addra <= 0;
118	                        end else begin
119	                            addra <= addra + 1;
120	                        end
121	                    end
122	                end
123	            end
124	
125	            S_GET_BASE: begin
126	                if (ram_delay) begin
127	                    lut_key <= lut_out;
128	                    ram_delay <= 0;
